import "../../../scss/Mureka_Recommend.scss"
import { useState, useEffect, useRef } from "react"


export function MurekaRecommend() {
  const [albums, setAlbums] = useState([]);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(null); // 현재 재생 중인 트랙 인덱스
  const audioRef = useRef(null);

  const reqTracks = [
    { trackName: "자유", artistName: "알레프 (ALEPH)" },
    { trackName: "Memory", artistName: "Anonymous Artists" },
    { trackName: "비하인드", artistName: "WOODZ" },
    { trackName: "Slo-mo", artistName: "GEMINI" },
    { trackName: "sowhereareyounow?", artistName: "Lokid" },
    { trackName: "The Stuff", artistName: "Lasse Lindh" },
    { trackName: "Dot", artistName: "Tuifu" },
    { trackName: "GoodBye", artistName: "SNSD" },
    { trackName: "어쩌다 보니", artistName: "데이식스" },
    { trackName: "우린 지금 어디쯤에 있는 걸까", artistName: "랄라스윗" },
  ];

  useEffect(() => {
    const fetchTracks = async () => {
      try {
        const results = await Promise.all(
          reqTracks.map(async ({ trackName, artistName }) => {
            try {
              const res = await fetch(
                `https://itunes.apple.com/search?term=${encodeURIComponent(artistName)}+${encodeURIComponent(trackName)}&entity=song&country=KR&limit=1`
              );
              const data = await res.json();
              return data.results[0] || null;
            } catch (error) {
              console.error(`Error fetching track ${artistName} - ${trackName}:`, error);
              return null;
            }
          })
        );
        setAlbums(results.filter(Boolean));
      } catch (error) {
        console.error("API 요청 중 오류 발생:", error);
        alert("API 요청 중 오류가 발생했습니다.");
      }
    };

    fetchTracks();
  }, []);

  const handlePlay = (index) => {
    if (currentTrackIndex !== index) {
      // 다른 트랙을 클릭한 경우
      if (audioRef.current) {
        audioRef.current.pause(); // 현재 재생 중인 트랙 멈추기
        audioRef.current.currentTime = 0; // 재생 시간 초기화
      }
      setCurrentTrackIndex(index); // 새 트랙 인덱스 설정
      audioRef.current = new Audio(albums[index].previewUrl); // 새 오디오 객체 생성
      audioRef.current.play(); // 새 트랙 재생
    } else {
      // 같은 트랙을 클릭한 경우
      if (audioRef.current) {
        audioRef.current.pause(); // 현재 트랙 멈추기
        setCurrentTrackIndex(null); // 재생 중인 트랙 인덱스 초기화
      }
    }
  };

  return (
    <section id="MurekaRecommend">
      <h2>MUREKA 추천 앨범 수록곡 TOP 10</h2>
      <div>
        {albums.map((track, index) => (
          <span
            key={index}
            className="RecommendChip"
            onClick={() => handlePlay(index)}
          >
            <img
              src={track.artworkUrl100.replace("100x100bb", "590x590bb")}
              alt="앨범 이미지"
            />
            <h4>{track.trackName}</h4>
            <h5>{track.artistName} - {track.collectionName}</h5>
          </span>
        ))}
      </div>
    </section>
  )
}
